root.js-content:
stp.writeLog("Begin: Assign function R2  023");
var GetTxId1= stp.getValue("/Document/MisMtchRjctnNtfctn/TxId","Id");
var GetTxId=GetTxId1[0];
var bu=stp.getTSUUnitCode();
var fld_list = stp.addFieldList(null,"C_MAIN_REF");    
var sql_condition = stp.addSQLCondition(null,"TSU_TID",GetTxId);
sql_condition     = stp.addSQLCondition(sql_condition,"C_UNIT_CODE",bu); 
sql_condition     = stp.addSQLCondition(sql_condition,"C_TRX_STATUS","M");
var result        = stp.executeQuery("TSUM_EM_BASELINE",fld_list,sql_condition);
var mainRef       = stp.getDBFieldValue(result,"C_MAIN_REF");
stp.writeLog("ref="+mainRef);
stp.updateFieldValue("/root/domData","C_MAIN_REF",mainRef);

var OurBIC=stp.getTSUBIC();
stp.writeLog("ourBIC="+OurBIC);

var TSU_REJT_AMDMB=0
stp.writeLog("TSU_REJT_AMDMB="+TSU_REJT_AMDMB);
stp.updateFieldValue("/root/domData/RjctdElmtMis","TSU_REJT_AMDMB",TSU_REJT_AMDMB);

//begin reqforactn
	var TSU_REQ_ACT_TP = stp.getValue("/Document/MisMtchRjctnNtfctn/ReqForActn","Tp");
	stp.writeLog("Request Action Type: "+TSU_REQ_ACT_TP[0]);
	if ( TSU_REQ_ACT_TP[0] ==undefined)
	{
	stp.updateFieldValue("/root/domData","TSUR2_REQ_ACT_TP","EMPT");
	stp.updateFieldValue("/root/domData","TSU_REQ_ACT_DESC","");
	stp.setNodeAttribute("/root/domData/TSU_REQ_ACT_DESC");
	}
//end reqforactn

//begin for tsu_rejt_rsn2
var MISMATCH_REJT_RSN= stp.getValue("/Document/MisMtchRjctnNtfctn/RjctnRsn/GblRjctnRsn","Desc");
var MISMATCH_REJT_ELMENT= stp.getValue("/Document/MisMtchRjctnNtfctn/RjctnRsn/RjctdElmt","ElmtSeqNb");

stp.writeLog("MISMATCH_REJT_RSN="+MISMATCH_REJT_RSN[0] );

if (MISMATCH_REJT_RSN[0]  != undefined)
{ 
	stp.updateFieldValue("/root/domData","TSU_REJT_RSNTP",1);
}
stp.writeLog("MISMATCH_REJT_ELMENT="+MISMATCH_REJT_ELMENT[0] );

if (MISMATCH_REJT_ELMENT[0] !=undefined)
{
	stp.updateFieldValue("/root/domData","TSU_REJT_RSNTP",2);
}
// end


var FirstREF1= stp.getValue("/Document/MisMtchRjctnNtfctn/UsrTxRef","Id");
var FirstREF = FirstREF1[0];
var FirstBIC1 = stp.getValue("/Document/MisMtchRjctnNtfctn/UsrTxRef/IdIssr","BIC");
var FirstBIC = FirstBIC1[0];
var SecondREF1 =stp.getValue("/Document/MisMtchRjctnNtfctn/UsrTxRef","Id");
var SecondREF = SecondREF1[1];
var SecondBIC1 =stp.getValue("/Document/MisMtchRjctnNtfctn/UsrTxRef/IdIssr","BIC");
var SecondBIC = SecondBIC1[1];

if (FirstREF== undefined)
{ FirstREF =null;
}
if (SecondREF == undefined)
{ SecondREF =null;
}

if(FirstBIC == undefined)
{FirstBIC =null;
}
if(SecondBIC == undefined )
{SecondBIC=null;
}


stp.writeLog("FirstREF= "+FirstREF);
stp.writeLog("FirstBIC="+FirstBIC);
stp.writeLog("SecondREF="+SecondREF);
stp.writeLog("SecondBIC= "+SecondBIC);

var BIC1 = stp.compareString(FirstBIC,OurBIC);
var BIC2 = stp.compareString(SecondBIC,OurBIC);
stp.writeLog("BIC1--------------------" +BIC1);
stp.writeLog("BIC2--------------------" +BIC2);

if(BIC1 == "true")
{
    stp.writeLog("--------------------------------------------------------BIC1=true     ");

    stp.updateFieldValue("/root/domData","TSU_OUR_BIC",FirstBIC);
    stp.updateFieldValue("/root/domData","TSU_OUR_REF",FirstREF);
    stp.updateFieldValue("/root/domData","TSU_THEIR_REF",SecondREF);
    stp.updateFieldValue("/root/domData","TSU_THEIR_BIC",SecondBIC);	

}

if(BIC2 == "true")
{
	stp.writeLog("----------------------------------BIC2=true     ");
    stp.updateFieldValue("/root/domData","TSU_OUR_BIC",SecondBIC);
    stp.updateFieldValue("/root/domData","TSU_OUR_REF",SecondREF);
    stp.updateFieldValue("/root/domData","TSU_THEIR_REF",FirstREF);
    stp.updateFieldValue("/root/domData","TSU_THEIR_BIC",FirstBIC);

}

stp.setAutoProcess(true);   
stp.setFunc("R2MisMatchRejectionNotification");
stp.writeLog("End: Assign function R2 023");
